const allRows = $input.all();

// 1. n8n 내장 라이브러리를 이용해 한국 시간(KST) 설정
const now = $now.setZone('Asia/Seoul');

// 2. 날짜 문자열 (YYYY.MM.DD)
const todayStr = now.toFormat('yyyy.MM.dd');

// 3. 제목 및 URL 설정 
const weekTitle = "3월 5주차"; // 직접 하드코딩

// 수시채용공고 URL
const myAppUrl = "https://job-finder-web-production.up.railway.app";

// D-Day 계산 함수 (Luxon 라이브러리 활용 버전)
function getDDay(deadlineStr) {
  if (!deadlineStr || deadlineStr === "9999-12-31" || deadlineStr === "") return "상시";
  const cleanDate = deadlineStr.replace(/\./g, '-').replace(/\s/g, '');
  const today = now.startOf('day'); 
  const targetDate = $now.constructor.fromISO(cleanDate).setZone('Asia/Seoul').startOf('day');
  const diffDays = Math.floor(targetDate.diff(today, 'days').days);

  if (diffDays === 0) return "D-Day";
  if (diffDays < 0) return "마감";
  return `D-${diffDays}`;
}

// 중복 제거 및 쉼표 합치기를 수행하는 함수
const cleanText = (val) => {
  if (!val) return "";
  let str = String(val).replace(/[\[\]'"]/g, "");
  let items = str.split(',').map(s => s.trim()).filter(i => i);
  return [...new Set(items)].join(', '); 
};

// 사용자별 데이터 그룹화
const usersMap = {};

for (const row of allRows) {
  const data = row.json;
  const email = data['이메일'];
  const type = data['레이어 구분'] || ""; 
  const sortingCriterion = data['정렬 구분'] || ""; 

  if (!usersMap[email]) {
    usersMap[email] = {
      userName: data['닉네임'] || "구독자", 
      userEmail: email,
      sortingCriterion: sortingCriterion,
      matchedJobs: [],
      explorationJobs: []
    };
  }

  const jobEntry = {
    company_name: cleanText(data['추천 기업명 (company_name)']),
    position_name: cleanText(data['추천 공고명 (job_title)']),
    job_role: cleanText(data['job_processed_position_name']), 
    employment_type: cleanText(data['job_processed_employment_type']) || "정규직",
    logo_url: data['기업로고 이미지URL'] || "",
    apply_url: data['채용공고URL (job_url)'] || "#",
    deadline: data['마감기한 일자 (deadline_date)'] || "9999-12-31", 
    rank: parseInt(data['rank']) || 999
  };

  if (type.includes("맞춤형")) {
    usersMap[email].matchedJobs.push(jobEntry);
  } else if (type.includes("탐색형")) {
    usersMap[email].explorationJobs.push(jobEntry);
  }
}

// 사용자별 정렬 로직
for (const email in usersMap) {
  const user = usersMap[email];
  const isRecommended = user.sortingCriterion.includes("추천순");
  const sortFn = (a, b) => isRecommended ? (a.rank - b.rank) : a.deadline.localeCompare(b.deadline);
  user.matchedJobs.sort(sortFn);
  user.explorationJobs.sort(sortFn);
}

// 잡 카드 생성 함수 (스마트 로고 처리)
function generateJobCard(job, userEmail, userName) {
  const dDay = getDDay(job.deadline);
  const params = [
    `url=${encodeURIComponent(job.apply_url)}`,
    `company=${encodeURIComponent(job.company_name)}`,
    `job_title=${encodeURIComponent(job.job_role)}`, 
    `recruitment_title=${encodeURIComponent(job.position_name)}`,
    `source=email`,
    `user_identifier=${encodeURIComponent(userName)}` 
  ].join('&');

  // GA를 위한 URL
  const applyUrl = `${myAppUrl}/?${params}`;

  // 로고 URL 검사
  const isUnreliableUrl = (url) => {
    if (!url) return true;
    const forbiddenDomains = ['namu.wiki', 'github.com'];
    return forbiddenDomains.some(domain => url.includes(domain));
  };

  // 로고 이미지 없을때
  const fallbackBox = `
    <div style="width:60px; height:60px; background-color:#ffffff; border:1px solid #E3E8EF; border-radius:8px; display:table; overflow:hidden;">
      <div style="display:table-cell; vertical-align:middle; text-align:center; font-size:10px; color:#666666; font-weight:bold; padding:2px; line-height:1.2; word-break:break-all;">
        ${job.company_name}
      </div>
    </div>`;

  // 최종 로고 이미지
  let logoContent = "";
  if (isUnreliableUrl(job.logo_url)) {
    logoContent = fallbackBox;
  } else {
    // 이미지와 폴백 박스가 겹치지 않도록 구조를 명확히 함
    logoContent = `
      <div style="width:60px; height:60px; position:relative;">
        <img src="${job.logo_url}" width="60" height="60" 
             style="border-radius:8px; display:block; object-fit:contain; background-color:#ffffff; border:1px solid #E3E8EF;"
             alt="${job.company_name}"
             onerror="this.style.display='none'; this.nextElementSibling.style.display='table';">
        <div style="display:none; width:60px; height:60px; background-color:#ffffff; border:1px solid #E3E8EF; border-radius:8px; overflow:hidden;">
          <div style="display:table-cell; vertical-align:middle; text-align:center; font-size:10px; color:#666666; font-weight:bold; padding:2px; line-height:1.2; word-break:break-all;">
            ${job.company_name}
          </div>
        </div>
      </div>`;
  }

  return `
<table width="600" style="width:600px !important; border:1px solid #E3E8EF; background-color:#F9FAFC; margin-bottom:12px; border-radius:10px; border-collapse:separate;" cellpadding="0" cellspacing="0">
  <tr><td style="padding:18px;"> 
    <table width="100%" cellpadding="0" cellspacing="0">
      <tr>
        <td width="60" valign="top" style="padding-right:15px; width:60px !important;"> 
          ${logoContent}
        </td>
        <td valign="top">
          <table width="100%" cellpadding="0" cellspacing="0" style="font-family:'Roboto', sans-serif; font-size:14px; line-height:1.8;"> 
            <tr><td width="55" style="color:#888888 !important; white-space:nowrap; text-align:left;">기업</td><td style="font-weight:bold; font-size:16px; color:#333333 !important; padding-left:10px; text-align:left;">${job.company_name}</td></tr>
            <tr><td width="55" style="color:#888888 !important; white-space:nowrap; text-align:left;">공고명</td><td style="font-size:15px; color:#333333 !important; padding-left:10px; text-align:left;">${job.position_name}</td></tr>
            <tr><td width="55" style="color:#888888 !important; white-space:nowrap; text-align:left;">고용형태</td><td style="white-space:nowrap; padding-left:10px; text-align:left;">
              <span style="display:inline-block; color:#007BFF !important; background-color:#E7F3FF !important; padding:2px 8px; border-radius:4px; font-weight:bold; font-size:11px;">신입</span>&nbsp;
              <span style="display:inline-block; color:#FD7E14 !important; background-color:#FFF3E6 !important; padding:2px 8px; border-radius:4px; font-weight:bold; font-size:11px;">${job.employment_type}</span>
            </td></tr>
            <tr><td width="55" style="color:#888888 !important; white-space:nowrap; text-align:left;">마감일자</td><td style="font-weight:bold; color:#333333 !important; white-space:nowrap; padding-left:10px; text-align:left;">
              <span style="${dDay === '마감' ? 'color:#888888 !important;' : 'color:#D93025 !important;'}">${dDay}</span>&nbsp;|&nbsp;${job.deadline === "9999-12-31" ? "상시채용" : job.deadline}
            </td></tr>
          </table>
        </td>
        <td width="75" align="right" valign="bottom" style="width:75px !important; white-space:nowrap;">
            <a href="${applyUrl}" target="_blank" style="font-family:'Roboto', sans-serif; font-size:12px; color:#333333 !important; text-decoration:none; border-bottom:1px solid #333333; font-weight:bold; white-space:nowrap; display:inline-block;">바로가기&nbsp;></a>
        </td>
      </tr>
    </table>
  </td></tr>
</table>`;
}

// 5. 최종 HTML 생성
const results = [];
for (const email in usersMap) {
  const user = usersMap[email];
  const badgeStyle = `background:#9BC988 !important; background-image:linear-gradient(#9BC988, #9BC988) !important; color:#000000 !important; font-weight:bold; font-size:14px; padding:10px 15px; border-radius:4px;`;
  const hrStyle = `border: 0; border-top: 1px solid #EEEEEE; margin: 40px 0;`;

  let matchedHtml = user.matchedJobs.length > 0 
    ? `<div style="${badgeStyle} margin-bottom:15px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="left" style="color:#000000 !important; font-weight:bold; font-size:14px; white-space:nowrap;">📌&nbsp;맞춤형&nbsp;채용공고</td><td align="right" style="color:#000000 !important; font-size:11px; font-weight:normal; opacity:0.7; white-space:nowrap;">${user.sortingCriterion}</td></tr></table></div>${user.matchedJobs.map(j => generateJobCard(j, user.userEmail, user.userName)).join("")}`
    : `<div style="${badgeStyle} margin-bottom:15px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="left" style="color:#000000 !important; font-weight:bold; font-size:14px; white-space:nowrap;">📌&nbsp;맞춤형&nbsp;채용공고</td><td align="right" style="color:#000000 !important; font-size:11px; font-weight:normal; opacity:0.7; white-space:nowrap;">${user.sortingCriterion}</td></tr></table></div><div style="text-align:center; padding:50px 20px; color:#333333 !important; font-size:15px; background-color:#ffffff; border:1px dashed #E3E8EF; border-radius:10px; margin-bottom:20px;"><b>이번&nbsp;주는&nbsp;AI기획자,&nbsp;AI&nbsp;리서치&nbsp;관련&nbsp;공고가&nbsp;줄어,<br>찾으시는&nbsp;채용공고가&nbsp;충분하지&nbsp;않을&nbsp;수&nbsp;있어요🥲</b><br><br>대신&nbsp;아래&nbsp;<b>${user.userName}님</b>이&nbsp;눈여겨&nbsp;보면&nbsp;좋을&nbsp;공고를&nbsp;추천해드려요!</div>`;

  const explorationTitle = user.matchedJobs.length > 0 ? `${user.userName}님이&nbsp;눈여겨&nbsp;보면&nbsp;좋을&nbsp;공고를&nbsp;추천해드려요!` : `Job&nbsp;Finder가&nbsp;${user.userName}님께&nbsp;추천하는&nbsp;공고`;
  const explorationHtml = user.explorationJobs.length > 0 
    ? `<div style="${hrStyle}"></div><div style="font-size:18px; color:#000000 !important; font-weight:bold; margin-top:30px; margin-bottom:15px;">${explorationTitle}</div><div style="${badgeStyle} margin-bottom:15px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="left" style="color:#000000 !important; font-weight:bold; font-size:14px; white-space:nowrap;">📌&nbsp;탐색형&nbsp;채용공고</td><td align="right" style="color:#000000 !important; font-size:11px; font-weight:normal; opacity:0.7; white-space:nowrap;"></td></tr></table></div>${user.explorationJobs.map(j => generateJobCard(j, user.userEmail, user.userName)).join("")}` 
    : `<div style="${hrStyle}"></div><div style="font-size:18px; color:#000000 !important; font-weight:bold; margin-top:30px; margin-bottom:15px;">${explorationTitle}</div><div style="${badgeStyle} margin-bottom:15px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td align="left" style="color:#000000 !important; font-weight:bold; font-size:14px; white-space:nowrap;">📌&nbsp;탐색형&nbsp;채용공고</td><td align="right" style="color:#000000 !important; font-size:11px; font-weight:normal; opacity:0.7; white-space:nowrap;"></td></tr></table></div><div style="text-align:center; padding:50px 20px; color:#333333 !important; font-size:15px; background-color:#ffffff; border:1px dashed #E3E8EF; border-radius:10px; margin-bottom:20px;"><b>금주&nbsp;탐색형&nbsp;채용공고가&nbsp;존재하지&nbsp;않아요.</b></div>`;

  const headerMent = user.sortingCriterion.includes("추천순") 
    ? `${user.userName}님이&nbsp;설정하신&nbsp;조건에&nbsp;적합한&nbsp;순으로&nbsp;보여드려요!`
    : `${user.userName}님&nbsp;맞춤형&nbsp;공고를&nbsp;마감기한&nbsp;순으로&nbsp;보여드려요!`;

  const fullHtml = `
<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd">
<html xmlns="http://www.w3.org/1999/xhtml" lang="ko">
<head>
  <meta http-equiv="Content-Type" content="text/html; charset=UTF-8" />
  <meta name="viewport" content="width=600" />
  <link href="https://fonts.googleapis.com/css2?family=Alatsi&family=Roboto:wght@400;700&display=swap" rel="stylesheet">
  <style type="text/css">
    [data-ogsc] .header-badge { background-color:#9BC988 !important; }
    [data-ogsc] span, [data-ogsc] td, [data-ogsc] div { color:#000000 !important; }
    .ExternalClass { width:100%; }
  </style>
</head>
<body style="margin:0; padding:0; background-color:#F4F4F4; font-family:'Roboto', sans-serif;">
  <center>
    <table width="600" style="width:600px !important; background-color:#F4F4F4; padding:20px 0;" cellpadding="0" cellspacing="0" border="0">
      <tr><td>
        <table width="600" style="width:600px !important; background-color:#ffffff; margin:0 auto; overflow:hidden; border-collapse:collapse;" cellpadding="0" cellspacing="0" border="0">
          <tr><td style="background-color:#3E5F44; padding:35px 25px;">
            <table width="100%" cellpadding="0" cellspacing="0" border="0">
              <tr>
                <td>
                  <div style="font-size:24px; font-weight:bold; margin-bottom:10px; color:#FFC93E !important;">🔎&nbsp;${weekTitle}&nbsp;채용공고&nbsp;도착!</div>
                  <div style="font-size:13px; color:#ffffff !important; opacity:0.9;">'바로가기'를&nbsp;클릭하면&nbsp;더&nbsp;자세한&nbsp;정보를&nbsp;확인하실&nbsp;수&nbsp;있어요.</div>
                </td>
                <td align="right" valign="bottom" style="font-size:12px; color:#ffffff !important; opacity:0.6;">${todayStr}</td>
              </tr>
            </table>
          </td></tr>

          <tr><td style="padding:35px 25px;">
            <div style="font-size:18px; color:#000000 !important; font-weight:bold; margin-bottom:30px;">${headerMent}</div>
            ${matchedHtml}
            ${explorationHtml}

            <div style="${hrStyle}"></div>
            <div style="text-align:center; margin-top:10px;">
              <div style="font-size:15px; font-weight:bold; color:#000000 !important; margin-bottom:18px;">Job&nbsp;Finder는&nbsp;직접&nbsp;선별한&nbsp;수시채용공고도&nbsp;제공하고&nbsp;있어요!</div>
              <a href="${myAppUrl}" target="_blank" style="display:inline-block; background-color:#3E5F44; color:#ffffff !important; padding:16px 35px; text-decoration:none; border-radius:6px; font-weight:bold; font-size:14px;">수시채용공고&nbsp;보러가기&nbsp;></a>
            </div>

            <div style="text-align:center; margin-top:50px; padding-top:35px; border-top:1px solid #EEEEEE;">
              <div style="font-size:22px; font-weight:bold; color:#000000 !important; margin-bottom:15px;">받아&nbsp;본&nbsp;채용공고가&nbsp;어떠셨나요?</div>
              <div style="font-size:14px; color:#666666 !important; line-height:1.7; margin-bottom:18px;">
                여러분의&nbsp;이용&nbsp;후기를&nbsp;들려주세요!<br>
                여러분의&nbsp;취업준비에&nbsp;더&nbsp;도움이&nbsp;되는&nbsp;서비스가&nbsp;되도록&nbsp;노력할게요.
              </div>
              <a href="https://docs.google.com/forms/d/e/1FAIpQLSdeQcQ9NGEeoWgbHdmI8mV73QOS11zse0-nfuIrTzr3q5MChw/viewform" target="_blank" style="font-size:14px; color:#333333 !important; font-weight:bold; text-decoration:underline;">서비스&nbsp;피드백하러&nbsp;가기</a>
            </div>
          </td></tr>

          <tr><td style="background-color:#E8E8E8; padding:45px 25px; text-align:center;">
            <div style="font-family:'Alatsi', sans-serif; font-size:26px; font-weight:bold; color:#3E5F44 !important; margin-bottom:20px;">JOB&nbsp;FINDER</div>

            <div style="margin-bottom:25px; line-height:2.2;">
              <a href="https://www.notion.so/JOB-FINDER-31dba24dd830809482f5c90f68796a89" target="_blank" style="color:#000000 !important; text-decoration:underline; font-weight:bold; font-size:15px;">JOB&nbsp;FINDER&nbsp;공식&nbsp;페이지</a><br>
              <a href="https://www.notion.so/JOB-FINDER-FAQ-6e2ba24dd8308254972f0166349e4af5?source=copy_link" target="_blank" style="color:#000000 !important; text-decoration:underline; font-weight:bold; font-size:15px;">FAQ</a>
            </div>

            <div style="font-size:15px; color:#3E5F44 !important; line-height:1.8;">
              <a href="https://half-stocking-169.notion.site/JOB-FINDER-314ba24dd83080839d3ad0a5454f9410" target="_blank" style="color:#3E5F44 !important; text-decoration:underline; font-weight:bold; font-size:15px; display:inline-block; margin-bottom:8px;">Job&nbsp;Finder를&nbsp;만든&nbsp;사람들</a><br>
              임소현&nbsp;|&nbsp;최지혜&nbsp;|&nbsp;김규연&nbsp;|&nbsp;박수민&nbsp;|&nbsp;이수진<br />
              최혜지&nbsp;|&nbsp;솔론&nbsp;|&nbsp;현재&nbsp;|&nbsp;황인성&nbsp;|&nbsp;김주은
            </div>

            <div style="margin-top:25px; font-size:11px; color:#999999 !important; line-height:1.6;">
              ※&nbsp;공고는&nbsp;발송&nbsp;시점&nbsp;이후에&nbsp;빠르게&nbsp;마감되거나&nbsp;열리지&nbsp;않을&nbsp;수&nbsp;있습니다.&nbsp;관심&nbsp;있는&nbsp;공고는&nbsp;조금&nbsp;더&nbsp;일찍&nbsp;확인해&nbsp;주시면&nbsp;좋아요!
            </div>
          </td></tr>

          <tr><td style="background-color:#3E5F44; height:10px;"></td></tr>
        </table>
      </td></tr>
    </table>
  </center>
</body>
</html>`;

  results.push({ json: { to: user.userEmail, subject: `[Job Finder] ${user.userName}님을 위한 이번 주 맞춤 공고가 도착했습니다!`, html: fullHtml } });
}

return results;
